function findRoundingError(prices, target) {
    const n = prices.length;
    const decimals = prices.map(price => {
        let num = parseFloat(price);
        return num - Math.floor(num);
    });

    const roundedSum = prices.reduce((sum, price) => {
        return sum + Math.floor(parseFloat(price));
    }, 0);

    if (target < roundedSum || target > roundedSum + n) {
        return '-1 ';
    }

    let ceilCount = target - roundedSum;
    let roundingError = 0;

    for (let d of decimals) {
        if (ceilCount > 0) {
            roundingError += 1 - d;
            ceilCount--;
        } else {
            roundingError += d;
        }
    }
    roundingError = roundingError.toFixed(3);
    return roundingError.toString() + " ";
}
```


    1. Convert the input `prices` to decimal numbers, and calculate the decimal parts (decimal array) using flooring or subtraction from the integer value.
2. Compute the sum of the floors (rounded sum) of the `prices`.
3. Check if the target is reachable (i.e., in the range of the rounded sum and the rounded sum + number of prices). If not, return "-1 ".
4. Calculate the number of ceiling operations needed (ceil_count).
5. Compute the smallest rounding error by iterating over the decimal array, subtracting the decimal value (using ceil operation) or adding it to the rounding error. The condition should depend on whether ceil_count is positive or not.
6. Return the result as a string with three decimal places.

